To create the authentication screens and integrate them into the profile panel as requested, I will:

1.  **Create a new `AuthForm` component**: This will handle both Sign In and Sign Up states with a minimalist design consistent with the app.
2.  **Update `App.tsx`**: Lift the authentication state (`isAuthenticated`) to the top level so it persists while the modal is open/closed during the session.
3.  **Update `ProfilePanel.tsx`**: Modify it to conditionally render the `AuthForm` when signed out, and the Profile details when signed in. The "Sign Out" button will trigger the state change.

Here are the updated files:

# Updated files:

## components/AuthForm.tsx

New component that provides a clean, minimalist form for signing in and signing up.

```tsx
/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
*/
import React, { useState } from 'react';
import { ShirtIcon } from './icons';

interface AuthFormProps {
  mode: 'signin' | 'signup';
  onToggleMode: () => void;
  onComplete: () => void;
}

const AuthForm: React.FC<AuthFormProps> = ({ mode, onToggleMode, onComplete }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    // Simulate network request for auth
    setTimeout(() => {
      setLoading(false);
      onComplete();
    }, 1500);
  };

  return (
    <div className="w-full flex flex-col items-center px-4 animate-fade-in">
       <div className="mb-8 flex flex-col items-center">
            <div className="w-12 h-12 bg-gray-900 rounded-xl flex items-center justify-center mb-4 shadow-lg">
                <ShirtIcon className="w-6 h-6 text-white" />
            </div>
            <h2 className="text-2xl font-serif font-bold text-gray-900 tracking-wide">
                {mode === 'signin' ? 'Welcome Back' : 'Join Vazi Check'}
            </h2>
            <p className="text-sm text-gray-500 mt-2 text-center max-w-[240px]">
                {mode === 'signin' 
                    ? 'Sign in to access your wardrobe and saved looks.' 
                    : 'Create an account to save your vibes.'}
            </p>
       </div>

       <form onSubmit={handleSubmit} className="w-full max-w-sm space-y-4">
            {mode === 'signup' && (
                <div className="space-y-1">
                    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider pl-1">Full Name</label>
                    <input 
                        type="text" 
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-gray-900 focus:ring-0 transition-colors text-sm bg-gray-50 focus:bg-white outline-none"
                        placeholder="Jane Doe"
                        required
                    />
                </div>
            )}

            <div className="space-y-1">
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider pl-1">Email Address</label>
                <input 
                    type="email" 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-gray-900 focus:ring-0 transition-colors text-sm bg-gray-50 focus:bg-white outline-none"
                    placeholder="name@example.com"
                    required
                />
            </div>

            <div className="space-y-1">
                <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-wider pl-1">Password</label>
                <input 
                    type="password" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-gray-900 focus:ring-0 transition-colors text-sm bg-gray-50 focus:bg-white outline-none"
                    placeholder="••••••••"
                    required
                />
            </div>

            {mode === 'signin' && (
                <div className="flex justify-end pr-1">
                    <button type="button" className="text-xs text-gray-500 hover:text-gray-900 transition-colors">Forgot Password?</button>
                </div>
            )}

            <button 
                type="submit" 
                disabled={loading}
                className="w-full bg-gray-900 text-white font-semibold py-3.5 rounded-xl shadow-lg hover:bg-gray-800 active:scale-[0.98] transition-all disabled:opacity-70 disabled:cursor-not-allowed mt-4"
            >
                {loading ? (
                    <span className="flex items-center justify-center gap-2">
                        <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                        Processing...
                    </span>
                ) : (
                    mode === 'signin' ? 'Sign In' : 'Create Account'
                )}
            </button>
       </form>

       <div className="mt-8 pt-6 border-t border-gray-100 w-full max-w-sm text-center">
            <p className="text-xs text-gray-500">
                {mode === 'signin' ? "Don't have an account?" : "Already have an account?"}
                <button 
                    onClick={onToggleMode}
                    className="ml-2 font-bold text-gray-900 hover:underline"
                >
                    {mode === 'signin' ? 'Sign Up' : 'Sign In'}
                </button>
            </p>
       </div>
    </div>
  );
};

export default AuthForm;
```

